INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-6f0ba476-moex-00484', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「楷書是字體中最整齊、最嚴謹的形式，唐人在書法上最大成就當屬『楷法』的創立，『法』 是法則、規律，從此以後，中國文字不再演化新的字體。唐以前的楷書是在追求一種法則下 進展的，三國時代的楷書仍帶有行書和隸書的筆勢，南朝楷書更加工整，但行書意味仍然濃 厚。北朝的魏碑體式多樣化，卻尚未尋找出它的規律性，隋代混同南北，成為唐楷的先驅。」 根據上文，下列選項正確的是：', '["唐人書法最大的特色是有書寫法則可以依循", "楷書的整齊嚴謹使它不得帶有行書隸書筆勢", "三國時代流行行書和隸書且沒有成熟的楷書", "南北朝楷書找到書寫規律性故表現趨勢一致 隋代能成為唐楷先驅是因其承襲南北朝發展"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00485', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「日子就這樣過去，消磨在管山管水裡。並不固執要去做什麼事，然而想來也沒什麼大後悔。 晚上入睡前，閉目感受周遭的寧靜，我總是心懷感激。大自然如此渺漠，卻又如此可親，和 我息息相關；我無法也不願割離。在黑暗中，我彷彿聽到了宇宙生命的呼吸和訓諭。我凝神 諦聽。時間緩緩流過。」 根據上文，下列選項符合文意的是：', '["抒發時光易逝的心中感慨", "顯露對於宇宙浩瀚的迷茫", "敘寫山居歲月的恬淡安然", "呈現離群索居的寂寞孤獨 表達對自然的敬畏與戀慕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00486', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '有位法國哲人為人道主義下定義：「一個人於河中快淹死，一百個人跳下河中相救，這一百 個人也許會因而淹死，而仍救不上那個人來。以一百比一，是件不理智的行動，我們把這種 行動叫做人道主義。因為救的不是那個『一』，而是救的那個『人』。」這種人道主義的昂 揚，是人類文明一大進程。由於人道主義的出現，率獸食人的社會才絕跡於人間。由於人道 主義的覺醒，以人祭天的犧牲才消弭於人世。 根據上文，下列選項何者屬於人道主義的表現？', '["國際紅十字會對受害者提供保護及救助", "國際貨幣基金組織長期致力於穩定匯率", "無國界醫生在衝突地區提供醫療及物資", "世界展望會幫助貧困兒童以及進行賑災 歐洲聯盟促進社會經濟發展及公民覺醒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00487', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「知識分子既不是調解者，也不是建立共識的人，而是全身投注於批評意識，不願接受簡單 的處方、現成的陳腔濫調，或平和寬容的肯定權勢者的說法或作法。他總是時時維持著警覺 狀態，永遠不讓似是而非的事物或約定俗成的觀念牽著鼻子走。」 根據上文，下列選項何者符合知識分子的特質？', '["不落俗套", "左右逢源", "通才碩學", "韜光養晦 慎思明辨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00488', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-34c7f7f6', 'sub-elementary-6f0ba476-02', NULL, 'single_choice', '「心理學的研究上有個現象叫做『破窗效應』，就是說，一個房子如果窗戶破了，沒有人去 修補，隔不久，其它的窗戶也會莫名其妙的被人打破；一面牆，如果出現一些塗鴉沒有清洗 掉，很快地，牆上就布滿了亂七八糟，不堪入目的東西。一個很乾淨的地方，人會不好意思 丟垃圾，但是一旦地上有垃圾出現之後，人就會毫不猶疑地拋，絲毫不覺羞愧。這真是很奇 怪的現象。」 根據上文，下列選項何者符合「破窗效應」的觀點？', '["管理時必須有統一的要求與準則", "防微杜漸是預防問題的手段之一", "人們很容易仿效他人不良的行為", "組織中引進競爭者可以激發活力 環境對人的行為具有強烈誘導性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00489', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '稅捐稽徵法所稱確定，下列敘述何者錯誤？', '["納稅義務人對稅捐稽徵機關核定補稅之案件，未於繳納稅款期間屆滿之翌日起30日內申請復查", "納稅義務人對稅捐稽徵機關核定稅額通知書所載無應納稅額，未在核定稅額通知書送達之翌日起30日 內，申請復查", "納稅義務人經復查決定後，未依法提起行政訴訟", "各稅法規定以公告代替核定稅額通知書之送達者，納稅義務人未於公告之翌日起30日內，申請復查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00490', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '111年度地價稅於111年11月1日至11月30日（周三非假日）徵收，陳君應繳稅額為8,000元，因故 遲致111年12月12日繳納，依稅捐稽徵法規定，應加徵滯納金為若干元？', '["240", "320", "400", "480"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00491', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '納稅義務人經稅捐稽徵機關查獲應補徵鉅額稅捐，不能於法定期間內繳清者，可向稅捐稽徵機關申請加 計利息分期繳納，依「納稅義務人申請加計利息分期繳納稅捐辦法」下列敘述何者錯誤？', '["稅捐稽徵機關每次核定補徵應繳稅款個人在新臺幣100萬元以上，得要求納稅義務人提供擔保", "稅捐稽徵機關每次核定補徵應繳稅款營利事業（包括機關團體）在新臺幣 150 萬元以上，得要求納稅 義務人提供擔保", "加計利息分期繳納，每期以一個月計算，分次繳納應繳稅款，最長以三十六期為限", "除滯報金、怠報金及罰鍰外，依各年度一月一日郵政儲金一年期定期儲金固定利率，按日加計利息， 一併徵收"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00492', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '甲公司民國111年度當年度有課稅所得新臺幣1,000萬元，另有核實計算上市公司證券交易所得（持有2年） 新臺幣200萬元，核實計算上市公司證券交易所得（持有滿3年）新臺幣700萬元，出售土地交易所得 新臺幣50萬元，試問該公司申報當年度基本稅額為若干？', '["222萬元", "180萬元", "160萬元", "114萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00493', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '李君為境內居住者，111年度獲取下列所得，依所得稅法規定何者應併入綜合所得總額？', '["投資海外基金獲配收益200萬元", "境內出書賺取版稅8萬元，境內演講鐘點費5萬元", "出售106年購入之房地，房地課稅所得為100萬元", "月領退休金8萬元，1年共領96萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
